<section class="portal-page narrow"><div class="confirmation-head"><span class="success-icon">✓</span><div><span class="eyebrow">APPOINTMENT DETAILS</span><h1><?=in_array($appointment['status'],['pending','confirmed'])?'Appointment Request Received':'Appointment Record'?></h1><p>Reference: <b><?=e($appointment['appointment_number'])?></b></p></div></div><article class="appointment-ticket"><div class="ticket-status"><span class="status-pill <?=e($appointment['status'])?>"><?=e(ucfirst($appointment['status']))?></span></div><div class="ticket-grid"><div><small>Doctor</small><h3><?=e($appointment['doctor_name'])?></h3><p><?=e($appointment['designation'])?></p></div><div><small>Department</small><h3><?=e($appointment['department_name'])?></h3></div><div><small>Date</small><h3><?=date('d F Y',strtotime($appointment['appointment_date']))?></h3></div><div><small>Time</small><h3><?=date('h:i A',strtotime($appointment['appointment_time']))?></h3></div><div><small>Consultation fee</small><h3>৳<?=number_format((float)$appointment['consultation_fee'])?></h3></div><div><small>Reason</small><p><?=e($appointment['reason'])?></p></div></div><p class="disclaimer">Please arrive at least 20 minutes early. Appointment time may change due to medical emergencies. Bring relevant documents and previous reports.</p></article><div class="action-row"><a class="btn outline" href="<?=url('appointments')?>">Appointment History</a><?php if(in_array($appointment['status'],['pending','confirmed'])):?><a class="btn" href="<?=url('appointment/reschedule?id='.$appointment['id'])?>">Reschedule</a><button class="btn danger" data-open-cancel>Cancel Appointment</button><?php endif;?></div><?php if(in_array($appointment['status'],['pending','confirmed'])):?><dialog id="cancel-dialog"><form method="post" action="<?=url('appointment/cancel')?>"><?=csrf_field()?><input type="hidden" name="id" value="<?=$appointment['id']?>"><h2>Cancel appointment?</h2><p>This will release the selected time slot.</p><label>Reason<textarea name="reason" rows="3" required></textarea></label><div class="action-row"><button type="button" class="btn outline" data-close-cancel>Keep Appointment</button><button class="btn danger">Confirm Cancellation</button></div></form></dialog><?php endif;?></section>

